body:
Surprising no one has filed an issue before now, but `$sformat` currently only works with a fixed format string.

Should fix UVM tests/70regs/90Mantis/6814

```
// verilog_format: off
`define stop $stop
`define checks(gotv,expv) do if ((gotv) != (expv)) begin $write("%%Error: %s:%0d:  got='%s' exp='%s'\n", `__FILE__,`__LINE__, (gotv), (expv)); `stop; end while(0);
`ifdef verilator
 `define no_optimize(v) $c(v)
`else
 `define no_optimize(v) (v)
`endif
// verilog_format: on

module t;

  function string cvt2string(input int width, input int v);
    string fmt;
    $sformat(fmt, "%0d'h%%%0dh", width, (width - 1) / 4 + 1);
    $sformat(cvt2string, {"FMT=", fmt}, v);
    $display("Format '%s' -> '%s'", fmt, cvt2string);
  endfunction

  initial begin
    string s;

    s = cvt2string(`no_optimize(2), `no_optimize(2 * 16));
    `checks(s, "FMT=2'h20");

    s = cvt2string(`no_optimize(14), `no_optimize(14 * 16));
    `checks(s, "FMT=14'h00e0");

    $finish;
  end

endmodule

```

